MODE YIELDINT = PROC(INT)VOID;
 
PROC gen factors = (INT n, YIELDINT yield)VOID: (
  FOR i FROM 1 TO ENTIER sqrt(n) DO
    IF n MOD i = 0 THEN
      yield(i); 
      INT other = n OVER i;
      IF i NE other THEN yield(n OVER i) FI
    FI
  OD
);
 
